BEGIN;

-- 0) Ensure current inventory schema exists (safe on drifted DBs)
CREATE TABLE IF NOT EXISTS inv_categories (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  name TEXT NOT NULL,
  normalized_name TEXT NOT NULL,
  sub_group TEXT DEFAULT 'Parts',
  created_at TIMESTAMPTZ DEFAULT NOW()
);
CREATE UNIQUE INDEX IF NOT EXISTS inv_categories_normalized_name_key ON inv_categories(normalized_name);

CREATE TABLE IF NOT EXISTS inv_products (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  category_id UUID NOT NULL REFERENCES inv_categories(id) ON DELETE CASCADE,
  name TEXT NOT NULL,
  normalized_name TEXT NOT NULL,
  created_at TIMESTAMPTZ DEFAULT NOW()
);
CREATE UNIQUE INDEX IF NOT EXISTS inv_products_category_id_normalized_name_key ON inv_products(category_id, normalized_name);

CREATE TABLE IF NOT EXISTS inv_variants (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  product_id UUID NOT NULL REFERENCES inv_products(id) ON DELETE CASCADE,
  name TEXT NOT NULL,
  normalized_name TEXT NOT NULL,
  width_m NUMERIC,
  unit TEXT NOT NULL DEFAULT 'pcs',
  purchase_rate NUMERIC,
  base_rate_sqm NUMERIC,
  created_at TIMESTAMPTZ DEFAULT NOW()
);
CREATE UNIQUE INDEX IF NOT EXISTS inv_variants_product_id_normalized_name_key ON inv_variants(product_id, normalized_name);

CREATE TABLE IF NOT EXISTS inv_rolls (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  variant_id UUID NOT NULL REFERENCES inv_variants(id) ON DELETE CASCADE,
  batch_code TEXT NOT NULL,
  original_length NUMERIC NOT NULL DEFAULT 0,
  remaining_length NUMERIC NOT NULL DEFAULT 0,
  unit TEXT NOT NULL DEFAULT 'm',
  purchase_rate NUMERIC,
  status TEXT NOT NULL DEFAULT 'in_stock',
  inward_date DATE,
  bill_no TEXT,
  supplier TEXT,
  stock_value NUMERIC,
  notes TEXT,
  created_at TIMESTAMPTZ DEFAULT NOW()
);
DROP INDEX IF EXISTS inv_rolls_batch_code_key;
CREATE INDEX IF NOT EXISTS idx_inv_rolls_batch_code ON inv_rolls(batch_code);

CREATE TABLE IF NOT EXISTS inv_movements (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  roll_id UUID REFERENCES inv_rolls(id) ON DELETE CASCADE,
  variant_id UUID REFERENCES inv_variants(id) ON DELETE CASCADE,
  movement_type TEXT NOT NULL,
  quantity NUMERIC NOT NULL DEFAULT 0,
  unit TEXT,
  rate NUMERIC,
  reference TEXT,
  note TEXT,
  performed_by UUID,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

